mapper.select:
SELECT * FROM ( /* 1. 관심동물 등록 */ SELECT 0 AS activityId, 'favorite' AS icon, 'pink' AS iconType, '''' || A.ANIMAL_NAME || ''' 을(를) 관심 목록에 추가했습니다.' AS description, TO_CHAR(F.CREATE_DATE, 'YYYY.MM.DD') AS actDate, 'primary' AS badgeType, '관심등록' AS badgeLabel FROM FAVORITE_ANIMAL F JOIN ANIMAL A ON F.ANIMAL_ID = A.ANIMAL_ID WHERE F.MEMBER_ID = #{memberId}
UNION ALL
/* 2. 후원 완료 */ SELECT 0 AS activityId, 'volunteer_activism' AS icon, 'green' AS iconType, TO_CHAR(D.DONATION_AMOUNT, 'FM999,999,999') || '원을 후원했습니다.' AS description, TO_CHAR(D.DONATION_DATE, 'YYYY.MM.DD') AS actDate, 'green' AS badgeType, '후원완료' AS badgeLabel FROM DONATION D WHERE D.MEMBER_ID = #{memberId}
UNION ALL
/* 3. 입양 신청 */ SELECT 0 AS activityId, 'assignment' AS icon, 'blue' AS iconType, '''' || A.ANIMAL_NAME || ''' 의 입양 신청서가 접수되었습니다.' AS description, TO_CHAR(AD.APPLY_DATE, 'YYYY.MM.DD') AS actDate, CASE AD.STATUS WHEN '승인' THEN 'green' WHEN '반려' THEN 'red' ELSE 'blue' END AS badgeType, AD.STATUS AS badgeLabel FROM ADOPTION AD JOIN ANIMAL A ON AD.ANIMAL_ID = A.ANIMAL_ID WHERE AD.MEMBER_ID = #{memberId}
UNION ALL
/* 4. 봉사 신청 */ SELECT 0 AS activityId, 'handshake' AS icon, 'orange' AS iconType, '''' || VR.TITLE || ''' 봉사활동을 신청했습니다.' AS description, TO_CHAR(VA.APPLY_DATE, 'YYYY.MM.DD') AS actDate, CASE VA.STATUS WHEN '승인' THEN 'emerald' WHEN '반려' THEN 'red' ELSE 'emerald' END AS badgeType, CASE VA.STATUS WHEN '승인' THEN '신청완료' WHEN '반려' THEN '취소됨' ELSE '승인대기' END AS badgeLabel FROM VOLUNTEER_APPLY VA JOIN VOLUNTEER_RECRUIT VR ON VA.RECRUIT_ID = VR.RECRUIT_ID WHERE VA.MEMBER_ID = #{memberId}
ORDER BY actDate DESC ) WHERE ROWNUM <= 5

