mapper.delete:
DELETE FROM FAVORITE_ANIMAL
 WHERE ANIMAL_ID = #{animalId}
   AND MEMBER_ID = #{memberId}

mapper.select:
SELECT COUNT(*)
  FROM ADOPTION
 WHERE MEMBER_ID = #{memberId}

   AND STATUS = #{status}

SELECT * FROM ( SELECT ROWNUM AS RNUM, T.* FROM ( SELECT AD.ADOPTION_ID AS adoptionId, AD.MEMBER_ID AS memberId, AD.ANIMAL_ID AS animalId, AD.VISIT_DATE AS visitDate, AD.APPLY_DATE AS applyDate, AD.STATUS AS status, AD.REJECT_REASON AS rejectReason, 'AD-' || TO_CHAR(AD.APPLY_DATE, 'YYYYMMDD') || '-' || LPAD(AD.ADOPTION_ID, 2, '0') AS adoptionNo, A.ANIMAL_NAME AS animalName, A.BREED AS breed, A.GENDER AS gender, A.AGE AS age, I.SAVE_FILE_NAME AS mainImage FROM ADOPTION AD JOIN ANIMAL A ON AD.ANIMAL_ID = A.ANIMAL_ID LEFT OUTER JOIN ANIMAL_IMAGE I ON A.ANIMAL_ID = I.ANIMAL_ID AND (I.IS_MAIN = 'Y' OR I.IS_MAIN IS NULL) WHERE AD.MEMBER_ID = #{memberId}
AND AD.STATUS = #{status}
ORDER BY AD.APPLY_DATE DESC ) T ) WHERE RNUM BETWEEN #{start} AND #{end}

mapper.delete:
DELETE FROM ADOPTION
 WHERE ADOPTION_ID = #{adoptionId}
   AND MEMBER_ID   = #{memberId}
   AND STATUS      = '심사중'

mapper.select:
SELECT COUNT(*)
  FROM BOARD
 WHERE MEMBER_ID = #{memberId}

   AND BOARD_TYPE = #{boardType}


   AND TITLE LIKE '%' || #{keyword} || '%'

SELECT * FROM ( SELECT ROWNUM AS RNUM, T.* FROM ( SELECT B.BOARD_ID AS boardId, B.MEMBER_ID AS memberId, B.BOARD_TYPE AS boardType, B.TITLE AS title, B.VIEW_COUNT AS viewCount, B.LIKE_COUNT AS likeCount, TO_CHAR(B.CREATE_DATE, 'YYYY.MM.DD') AS createDate, (SELECT COUNT(*) FROM BOARD_COMMENT C WHERE C.BOARD_ID = B.BOARD_ID) AS commentCount FROM BOARD B WHERE B.MEMBER_ID = #{memberId}
AND B.BOARD_TYPE = #{boardType}
AND B.TITLE LIKE '%' || #{keyword} || '%'
ORDER BY B.BOARD_ID DESC ) T ) WHERE RNUM BETWEEN #{start} AND #{end}

mapper.delete:
DELETE FROM BOARD
 WHERE BOARD_ID  = #{boardId}
   AND MEMBER_ID = #{memberId}

